#include<bits/stdc++.h>
using namespace std;
int maxx=INT_MIN,maxy=INT_MIN,minx=INT_MAX,miny=INT_MAX;
int main(){
    for(int i=1;i<=4;i++){
        int x,y;
        cin>>x>>y;
        maxx=max(maxx,x);
        minx=min(minx,x);
        maxy=max(maxy,y);
        miny=min(miny,y);
    }
    cout<<(maxx-minx)*(maxy-miny);
}
